const body = $input.first().json.body || {};
const countries = body.countries || ['BRA','USA','CHN','IND','DEU','KOR','ZAF','FIN','NGA','ETH'];
const indicators = body.indicators || ['SE.XPD.TOTL.GD.ZS','SE.PRM.ENRR','SE.SEC.ENRR','SE.TER.ENRR'];

const BASELINES = { 'SE.XPD.TOTL.GD.ZS': {'FIN':6.8,'SWE':7.1,'GBR':5.5,'FRA':5.4,'DEU':4.9,'USA':5.0,'KOR':4.9,'JPN':3.6,'BRA':5.8,'CHN':3.8,'IND':3.8,'MEX':4.9,'ARG':5.5,'COL':4.5,'ZAF':6.2,'NGA':2.8,'ETH':4.5,'RUS':4.1}, 'SE.PRM.ENRR': {'FIN':98,'SWE':99,'GBR':102,'FRA':105,'DEU':103,'USA':100,'KOR':101,'BRA':118,'CHN':112,'IND':108,'MEX':109,'ZAF':104,'NGA':85,'ETH':91,'RUS':101}, 'SE.SEC.ENRR': {'FIN':130,'SWE':133,'GBR':123,'FRA':112,'DEU':104,'USA':98,'KOR':98,'BRA':100,'CHN':87,'IND':63,'ZAF':98,'NGA':41,'ETH':35,'RUS':107}, 'SE.TER.ENRR': {'FIN':88,'SWE':72,'GBR':61,'FRA':65,'DEU':70,'USA':88,'KOR':95,'BRA':48,'CHN':48,'IND':25,'ZAF':21,'NGA':10,'ETH':8,'RUS':81}, 'SE.PRM.CMPT.ZS': {'FIN':99,'GBR':99,'USA':98,'KOR':99,'BRA':97,'CHN':95,'IND':88,'ZAF':98,'NGA':69,'ETH':52,'RUS':99}, 'SE.ADT.LITR.ZS': {'FIN':99,'GBR':99,'USA':99,'KOR':99,'BRA':91,'CHN':95,'IND':73,'ZAF':87,'NGA':60,'ETH':51,'RUS':99} };
const NAMES = {'BRA':'Brazil','USA':'United States','CHN':'China','IND':'India','DEU':'Germany','FRA':'France','GBR':'United Kingdom','JPN':'Japan','KOR':'Korea, Rep.','MEX':'Mexico','ARG':'Argentina','COL':'Colombia','ZAF':'South Africa','NGA':'Nigeria','ETH':'Ethiopia','EGY':'Egypt, Arab Rep.','IDN':'Indonesia','TUR':'Turkiye','SAU':'Saudi Arabia','RUS':'Russian Federation','CHL':'Chile','PER':'Peru','FIN':'Finland','SWE':'Sweden'};
const LABELS = {'SE.XPD.TOTL.GD.ZS':'Gasto publico em educacao (% PIB)','SE.PRM.ENRR':'Matricula primaria (bruta %)','SE.SEC.ENRR':'Matricula secundaria (bruta %)','SE.TER.ENRR':'Matricula terciaria (bruta %)','SE.PRM.CMPT.ZS':'Conclusao primaria (%)','SE.ADT.LITR.ZS':'Alfabetizacao adultos (%)'};

// analise_data: enviado pelo dashboard.py com os dados REAIS ja processados pelo pipeline.py
// (fallback sintetico abaixo so' e usado se o dashboard nao enviar analise_data)
const precomputed = body.analise_data;
let records;
if (precomputed && Array.isArray(precomputed) && precomputed.length > 0) {
  records = precomputed;
} else {
  const actC = countries.filter(c => NAMES[c]);
  const actI = indicators.filter(i => LABELS[i]);
  records = [];
  for (const cc of actC) {
    for (const ic of actI) {
      const base = (BASELINES[ic] || {})[cc] || 50;
      const isDev = ['NGA','ETH','IND','IDN','EGY','PER','COL','CHN','BRA'].includes(cc);
      const trend = isDev ? (Math.random()*1.2+0.3) : (Math.random()*0.7-0.2);
      const vS = base;
      let v = base;
      for (let y=0;y<19;y++) { v = Math.max(1, v+trend+(Math.random()-0.5)*base*0.03); }
      const gPct = vS>0 ? ((v-vS)/Math.abs(vS))*100 : 0;
      const cagr = vS>0 ? (Math.pow(v/vS,1/19)-1)*100 : 0;
      records.push({country_code:cc,country_name:NAMES[cc],indicator_code:ic,indicator_label:LABELS[ic],val_start:Math.round(vS*100)/100,val_end:Math.round(v*100)/100,growth_pct:Math.round(gPct*100)/100,cagr:Math.round(cagr*1000)/1000});
    }
  }
}

const byI = {};
for (const r of records) { if(!byI[r.indicator_code])byI[r.indicator_code]=[]; byI[r.indicator_code].push(r); }
const topG = Object.entries(byI).map(([c,rows])=>({indicador:rows[0].indicator_label+' ('+c+')',top5:rows.sort((a,b)=>b.growth_pct-a.growth_pct).slice(0,5)}));
const bottom = [].concat(records).sort((a,b)=>a.growth_pct-b.growth_pct).slice(0,8);
const inv = records.filter(r=>r.indicator_code==='SE.XPD.TOTL.GD.ZS').sort((a,b)=>b.val_end-a.val_end).slice(0,5);

const schema = '{"paises_em_evolucao":[{"pais":"string","indicador":"string","taxa_crescimento":"string","destaque":"string"}],"paises_estagnados":[{"pais":"string","indicador":"string","periodo_observado":"string","observacao":"string"}],"maior_investimento":[{"pais":"string","valor_percentual":"string","relacao_desempenho":"string"}],"melhores_indicadores":[{"pais":"string","justificativa":"string","indicadores_destaque":["string"]}],"explicacoes":[{"hipotese":"string","evidencia":"string","nivel_confianca":"baixo|medio|alto"}],"recomendacoes":[{"recomendacao":"string","publico_alvo":"string","prioridade":"alta|media|baixa"}],"sumario_executivo":"string"}';

const prompt = 'Analise os dados educacionais do World Bank EdStats para ' + countries.length + ' paises (2000-2020).\n\nTOP CRESCIMENTO POR INDICADOR:\n' + JSON.stringify(topG,null,2) + '\n\nPAISES COM MENOR CRESCIMENTO (ESTAGNACAO):\n' + JSON.stringify(bottom,null,2) + '\n\nMAIORES INVESTIDORES (% PIB em Educacao):\n' + JSON.stringify(inv,null,2) + '\n\nResponda EXCLUSIVAMENTE com um objeto JSON valido, sem texto adicional, sem markdown, sem comentarios. Estrutura obrigatoria:\n' + schema;

return [{json:{prompt,n_records:records.length,n_countries:countries.length,source:precomputed?'streamlit':'sintetico'}}];

