const raw = $input.first().json.output;
let analysis = null;
let errorMsg = null;

if (raw && typeof raw === 'object') {
  analysis = raw;
} else if (typeof raw === 'string') {
  try {
    let jsonStr = raw.trim();
    const mdMatch = jsonStr.match(/```(?:json)?\s*([\s\S]*?)\s*```/);
    if (mdMatch) jsonStr = mdMatch[1].trim();
    const s = jsonStr.indexOf('{');
    const e = jsonStr.lastIndexOf('}');
    if (s !== -1 && e !== -1) jsonStr = jsonStr.slice(s, e+1);
    analysis = JSON.parse(jsonStr);
  } catch (ex) {
    errorMsg = 'Falha ao parsear saida do agente: ' + ex.message + '. Output: ' + String(raw).substring(0, 300);
  }
} else {
  errorMsg = 'AI Agent nao retornou output esperado.';
}

const requiredKeys = ['paises_em_evolucao','paises_estagnados','maior_investimento','melhores_indicadores','explicacoes','recomendacoes','sumario_executivo'];
const missingKeys = analysis ? requiredKeys.filter(k => !analysis[k]) : requiredKeys;

return [{json:{
  status: analysis && missingKeys.length === 0 ? 'success' : 'error',
  analysis: analysis || null,
  error: errorMsg || (missingKeys.length > 0 ? 'Campos ausentes: '+missingKeys.join(',') : null),
  model: 'claude-sonnet-4-6',
  usage: {},
  campos_presentes: analysis ? Object.keys(analysis) : [],
  timestamp: new Date().toISOString()
}}];
